namespace sv_39bd71cbe030468699d5c25ad946ddfe.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@rendermode InteractiveServer
@using sv_39bd71cbe030468699d5c25ad946ddfe.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <!-- Left sidebar: channel list -->
    <aside class="channel-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @if (_channels is not null)
            {
                @foreach (var channel in _channels)
                {
                    <li class="channel-item @(channel.Id == _activeChannelId ? "active" : "")"
                        @onclick="() => SelectChannelAsync(channel)">
                        <div class="channel-name"># @channel.Name</div>
                        <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                        @if (channel.UnreadCount > 0)
                        {
                            <span class="unread-badge">@channel.UnreadCount</span>
                        }
                    </li>
                }
            }
        </ul>
    </aside>

    <!-- Main message area -->
    <section class="message-area @(_threadOpen ? "" : "expanded")">
        @if (_activeChannel is not null)
        {
            <div class="message-header">
                <h2># @_activeChannel.Name</h2>
                <p>@_activeChannel.Description</p>
            </div>

            <div class="message-list" @ref="_messageListRef" @onscroll="OnMessageListScroll">
                @if (_loadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @if (_messages is not null)
                {
                    @foreach (var msg in _messages)
                    {
                        <div class="message-bubble" @onmouseenter="() => _hoveredMessageId = msg.Id"
                             @onmouseleave="() => _hoveredMessageId = null">
                            <div class="message-top">
                                <span class="msg-author">@msg.Author</span>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @if (_threadSummaries.TryGetValue(msg.Id, out var summary))
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg)">
                                    @summary.ReplyCount replies
                                </button>
                            }

                            @if (_hoveredMessageId == msg.Id)
                            {
                                <div class="msg-actions">
                                    <button class="action-btn" @onclick="() => OpenThreadAsync(msg)" title="Reply in thread">
                                        💬 Reply
                                    </button>
                                    <div class="emoji-picker-wrapper">
                                        <button class="action-btn" @onclick="() => ToggleEmojiPicker(msg.Id)" title="Add reaction">
                                            😀 React
                                        </button>
                                        @if (_emojiPickerMessageId == msg.Id)
                                        {
                                            <div class="emoji-picker">
                                                @foreach (var emoji in _commonEmojis)
                                                {
                                                    <button class="emoji-option" @onclick="() => ReactAsync(msg.Id, emoji)">
                                                        @emoji
                                                    </button>
                                                }
                                            </div>
                                        }
                                    </div>
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newMessageText" @bind:event="oninput"
                          placeholder="Type a message…"
                          @onkeydown="OnMessageKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(_newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    <!-- Right panel: thread view -->
    @if (_threadOpen && _threadRootMessage is not null)
    {
        <aside class="thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-btn" @onclick="CloseThread" title="Close thread">✕</button>
            </div>

            <div class="thread-root-quote">
                <span class="msg-author">@_threadRootMessage.Author</span>
                <span class="msg-time">@FormatRelativeTime(_threadRootMessage.SentAt)</span>
                <div class="msg-content">@_threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @if (_threadMessages is not null)
                {
                    @foreach (var reply in _threadMessages)
                    {
                        <div class="message-bubble thread-reply">
                            <div class="message-top">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>
                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    }
                }
            </div>

            <div class="message-input-area">
                <textarea @bind="_newReplyText" @bind:event="oninput"
                          placeholder="Reply in thread…"
                          @onkeydown="OnReplyKeyDown" rows="2"></textarea>
                <button class="send-btn" @onclick="SendReplyAsync" disabled="@string.IsNullOrWhiteSpace(_newReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private int _skip;
    private bool _loadingMore;
    private bool _allMessagesLoaded;
    private string _newMessageText = "";

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _newReplyText = "";

    // Hover / picker state
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allMessagesLoaded = false;
        _messages = null;
        _emojiPickerMessageId = null;
        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _skip = messages.Count;
        if (messages.Count < PageSize) _allMessagesLoaded = true;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        UpdateChannelUnread(channel.Id);

        await ScrollToBottom();
    }

    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allMessagesLoaded || _messages is null || _activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count < PageSize) _allMessagesLoaded = true;

        _messages.InsertRange(0, older);
        _skip += older.Count;
        BuildThreadSummaries();
        _loadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;
        _threadSummaries.Clear();

        // Group messages that are replies to build thread summaries
        var replies = _messages.Where(m => m.ReplyToId.HasValue).GroupBy(m => m.ReplyToId!.Value);
        foreach (var group in replies)
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
        _newReplyText = "";
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _newReplyText = "";
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages?.Add(sent);
        _newMessageText = "";
        _skip++;

        await ScrollToBottom();
    }

    private async Task SendReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_newReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _newReplyText.Trim(), _threadRootMessage.Id);
        _threadMessages?.Add(reply);
        _messages?.Add(reply);
        _newReplyText = "";
        _skip++;

        BuildThreadSummaries();
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Optimistic update: add reaction locally
        AddReactionLocally(_messages, messageId, emoji);
        AddReactionLocally(_threadMessages, messageId, emoji);
    }

    private static void AddReactionLocally(List<Message>? messages, int messageId, string emoji)
    {
        if (messages is null) return;
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OnReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReplyAsync();
        }
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 50 ? desc[..47] + "…" : desc;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

