@code {
    private const int PageSize = 30;
    private static readonly string[] _commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private List<Channel>? _channels;
    private int? _activeChannelId;
    private Channel? _activeChannel;
    private List<Message>? _messages;
    private Dictionary<int, ThreadSummary> _threadSummaries = new();
    private int _skip;
    private bool _loadingMore;
    private bool _allMessagesLoaded;
    private string _newMessageText = "";

    // Thread state
    private bool _threadOpen;
    private Message? _threadRootMessage;
    private List<Message>? _threadMessages;
    private string _newReplyText = "";

    // Hover / picker state
    private int? _hoveredMessageId;
    private int? _emojiPickerMessageId;

    private ElementReference _messageListRef;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        if (_activeChannelId == channel.Id) return;

        _activeChannelId = channel.Id;
        _activeChannel = channel;
        _skip = 0;
        _allMessagesLoaded = false;
        _messages = null;
        _emojiPickerMessageId = null;
        CloseThread();

        var messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        _messages = messages;
        _skip = messages.Count;
        if (messages.Count < PageSize) _allMessagesLoaded = true;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);
        UpdateChannelUnread(channel.Id);

        await ScrollToBottom();
    }

    private async Task OnMessageListScroll()
    {
        if (_loadingMore || _allMessagesLoaded || _messages is null || _activeChannelId is null) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop > 50) return;

        _loadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(_activeChannelId.Value, _skip, PageSize);
        if (older.Count < PageSize) _allMessagesLoaded = true;

        _messages.InsertRange(0, older);
        _skip += older.Count;
        BuildThreadSummaries();
        _loadingMore = false;
    }

    private void BuildThreadSummaries()
    {
        if (_messages is null) return;
        _threadSummaries.Clear();

        // Group messages that are replies to build thread summaries
        var replies = _messages.Where(m => m.ReplyToId.HasValue).GroupBy(m => m.ReplyToId!.Value);
        foreach (var group in replies)
        {
            _threadSummaries[group.Key] = new ThreadSummary(
                group.Key,
                group.Count(),
                group.Max(m => m.SentAt)
            );
        }
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        _threadRootMessage = rootMessage;
        _threadMessages = await ChatService.GetThreadAsync(rootMessage.Id);
        _threadOpen = true;
        _newReplyText = "";
    }

    private void CloseThread()
    {
        _threadOpen = false;
        _threadRootMessage = null;
        _threadMessages = null;
        _newReplyText = "";
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(_newMessageText) || _activeChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(_activeChannelId.Value, _newMessageText.Trim(), null);
        _messages?.Add(sent);
        _newMessageText = "";
        _skip++;

        await ScrollToBottom();
    }

    private async Task SendReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(_newReplyText) || _threadRootMessage is null || _activeChannelId is null) return;

        var reply = await ChatService.SendMessageAsync(_activeChannelId.Value, _newReplyText.Trim(), _threadRootMessage.Id);
        _threadMessages?.Add(reply);
        _messages?.Add(reply);
        _newReplyText = "";
        _skip++;

        BuildThreadSummaries();
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        _emojiPickerMessageId = null;

        // Optimistic update: add reaction locally
        AddReactionLocally(_messages, messageId, emoji);
        AddReactionLocally(_threadMessages, messageId, emoji);
    }

    private static void AddReactionLocally(List<Message>? messages, int messageId, string emoji)
    {
        if (messages is null) return;
        var idx = messages.FindIndex(m => m.Id == messageId);
        if (idx < 0) return;

        var msg = messages[idx];
        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, new List<string> { "You" }));
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        _emojiPickerMessageId = _emojiPickerMessageId == messageId ? null : messageId;
    }

    private void UpdateChannelUnread(int channelId)
    {
        if (_channels is null) return;
        var idx = _channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            var ch = _channels[idx];
            _channels[idx] = ch with { UnreadCount = 0 };
        }
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    private async Task OnReplyKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReplyAsync();
        }
    }

    private async Task ScrollToBottom()
    {
        await Task.Yield();
        await JS.InvokeVoidAsync("eval",
            "let el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight;");
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 50 ? desc[..47] + "…" : desc;
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        if (diff.TotalSeconds < 60) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

